@InternalCoilApi
actual object ServiceLoaderComponentRegistry {
    // This code is written intentionally so R8 can optimize it:
    // https://github.com/Kotlin/kotlinx.coroutines/issues/1231
    actual val fetchers by lazy {
        ServiceLoader.load(
            FetcherServiceLoaderTarget::class.java,
            FetcherServiceLoaderTarget::class.java.classLoader,
        ).iterator().asSequence().toList().toImmutableList()
    }
    actual val decoders by lazy {
        ServiceLoader.load(
            DecoderServiceLoaderTarget::class.java,
            DecoderServiceLoaderTarget::class.java.classLoader,
        ).iterator().asSequence().toList().toImmutableList()
    }

    actual fun register(fetcher: FetcherServiceLoaderTarget<*>) {
        throw UnsupportedOperationException()
    }

    actual fun register(decoder: DecoderServiceLoaderTarget) {
        throw UnsupportedOperationException()
    }
}

package coil3.util

import coil3.annotation.InternalCoilApi
import kotlinx.atomicfu.locks.SynchronizedObject
import kotlinx.atomicfu.locks.synchronized

@InternalCoilApi
actual object ServiceLoaderComponentRegistry {

    private val lock = SynchronizedObject()
    private val _fetchers = mutableListOf<FetcherServiceLoaderTarget<*>>()
    private val _decoders = mutableListOf<DecoderServiceLoaderTarget>()

    actual val fetchers: List<FetcherServiceLoaderTarget<*>>
        get() = synchronized(lock) { _fetchers.toImmutableList() }

    actual val decoders: List<DecoderServiceLoaderTarget>
        get() = synchronized(lock) { _decoders.toImmutableList() }

    actual fun register(fetcher: FetcherServiceLoaderTarget<*>) = synchronized(lock) {
        _fetchers += fetcher
    }

    actual fun register(decoder: DecoderServiceLoaderTarget) = synchronized(lock) {
        _decoders += decoder
    }
}

